import React, { useState, useEffect } from 'react';
import { X, User, Mail, Smartphone } from 'lucide-react';
import api from '../../api/api';
import { toast } from 'react-toastify';
import '../../assets/styles/ProfileModal.css';

const ProfileModal = ({ isOpen, onClose, user, onUpdateSuccess }) => {
  const [formData, setFormData] = useState({
    username: '',
    email: '',
    mobileNo: ''
  });
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (user && isOpen) {
      setFormData({
        username: user.username || '',
        email: user.email || '',
        mobileNo: user.mobileNo || ''
      });
    }
  }, [user, isOpen]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const data = await api.put('/api/auth/profile', formData);
      if (data.success) {
        toast.success('Profile updated successfully!');
        window.dispatchEvent(new Event('authChange'));
        onUpdateSuccess();
        onClose();
      }
    } catch (err) {
      const msg = err.response?.data?.message || 'Update failed.';
      toast.error(msg);
    } finally {
      setLoading(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="profile-modal-overlay">
      <div className="profile-modal">
        <button className="profile-close-btn" onClick={onClose} aria-label="Close">
          <X size={24} />
        </button>

        <div className="profile-header">
          <div className="profile-icon-ring"><User size={32} /></div>
          <h2>Edit Profile</h2>
          <p>Update your personal information for a better Heritage Harvest experience.</p>
        </div>

        <form className="profile-form" onSubmit={handleSubmit}>
          <div className="form-group-profile">
            <label><User size={14} /> Full Name</label>
            <input 
              type="text" 
              value={formData.username} 
              onChange={e => setFormData({...formData, username: e.target.value})} 
              required 
              placeholder="Your Name"
            />
          </div>

          <div className="form-group-profile">
            <label><Mail size={14} /> Email Address</label>
            <input 
              type="email" 
              value={formData.email} 
              onChange={e => setFormData({...formData, email: e.target.value})} 
              required 
              placeholder="you@example.com"
            />
          </div>

          <div className="form-group-profile">
            <label><Smartphone size={14} /> Mobile Number</label>
            <input 
              type="tel" 
              value={formData.mobileNo} 
              onChange={e => setFormData({...formData, mobileNo: e.target.value})} 
              required 
              placeholder="+91 XXXXX XXXXX"
            />
          </div>

          <button type="submit" className="profile-submit-btn" disabled={loading}>
            {loading ? 'Saving Changes...' : 'Update Profile'}
          </button>
        </form>
      </div>
    </div>
  );
};

export default React.memo(ProfileModal);
